parameters.value:
=mutation GrabTOCAndHTMLWithURL {
  goto(url: "{{ $('Set Inputs').item.json.Source }}", waitUntil: networkIdle) {
    status
    url
  }

  pause: waitForTimeout(time: 1500) {
    time
  }

  # Capture the main HTML document response + headers
  documentResponse: response(type: [document], wait: false) {
    url
    status
    headers {
      name
      value
    }
  }

  # Capture JavaScript responses + headers
  scripts: response(type: [script], wait: false) {
    url
    headers {
      name
      value
    }
    body
  }

  finalUrl: url {
    url
  }

  fullHtml: html {
    html
  }
}
